      caseInfo.patientName,
      caseInfo.id
    );
    const ctx =
      `CASO: ${caseInfo.title}. Paciente: ${patientRef}, ${caseInfo.species},` +
      `${caseInfo.breed}, ${caseInfo.ageYears} anos, ${caseInfo.weightKg}kg.` +
