          content: (
            caseInfo.status === 'completed'
              ? `${ctx}\n\nAvalie a evolução pós-operatória. Máx. 120 palavras: evolução clínica, achados atuais, prognóstico e condutas recomendadas.`
              : caseInfo.status === 'critical'
